    [Header("Debug")]
    public bool debug = false;

    [Header("State")]
    public bool isOn = false;
    public float timeToOnMin = 3f;
    public float timeToOnMax = 3f;
    public float timeToOn;
    [SerializeField]
    private float timeToOnDelta = 0f;
    [SerializeField]
    private bool shouldTurnOn = false;

