            }
        }
        this.pSystem.Stop();
        for (int s = 0; s < particleSystems.Length; s++)
        {
            ParticleSystem system = (ParticleSystem)particleSystems[s];
            system.Stop();
        }
    }

    private IEnumerator TurnOnSprite()
    {
        Component[] particleSystems = GetComponentsInChildren(typeof(ParticleSystem));
        for (int s = 0; s < particleSystems.Length; s++)
        {
            ParticleSystem system = (ParticleSystem)particleSystems[s];
